SELECT keyid, name, address, field, remark, add_time, update_time
FROM test..haosen_name_addr WITH(NOLOCK)


        AND keyid LIKE '%' + #{condition.keyid} + '%'


        AND name LIKE '%' + #{condition.name} + '%'


        AND address LIKE '%' + #{condition.address} + '%'


        AND remark LIKE '%' + #{condition.remark} + '%'


        AND add_time >= #{condition.startTime}


        AND add_time <= #{condition.endTime}


        AND update_time >= #{condition.updateStartTime}


        AND update_time <= #{condition.updateEndTime}


ORDER BY add_time DESC

SELECT keyid, name, address, field, remark, add_time, update_time
FROM test..haosen_name_addr WITH(NOLOCK)
WHERE keyid = #{keyid}

